func TestIntegrationWillRunInstrumentationServerWhenTargetHasNoHttpServer(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping integration test")
	}
	dbType := os.Getenv("GRAFANA_TEST_DB")
	if dbType == "" {
		t.Skip("skipping - GRAFANA_TEST_DB not defined")
	}
	if dbType == "sqlite3" {
